def _full_query() -> str:
    return "SELECT * FROM orders WHERE email = %s"


def fetch_rows(conn: pymysql.connections.Connection, value: str):
    sql = _full_query()
    with conn.cursor(DictCursor) as cur:
        cur.execute(sql, (value,))
        return cur.fetchall()

from sqlalchemy import text
from sqlalchemy.orm import Session


def fetch_rows(session: Session, value: str):
    stmt = text("SELECT * FROM sessions WHERE password_hash = :v")
    return session.execute(stmt, {"v": value}).fetchall()

import sqlite3


def fetch_rows(conn: sqlite3.Connection, value: str):
    sql = "SELECT * FROM audit_log WHERE user_id = ?"
    cur = conn.cursor()
    cur.execute(sql, (value,))
    return cur.fetchall()

